const input = $input.first().json;
const action = input.action || 'search_station';
const BASE = 'https://openservice-test.vrr.de/openservice';
const EFA_VERSION = '10.4.18.18';
const HEADERS = { 'Accept': 'application/json', 'User-Agent': 'n8n-claw-oepnv/1.0' };

function buildQs(params) {
  const parts = [];
  for (const k of Object.keys(params)) {
    parts.push(encodeURIComponent(k) + '=' + encodeURIComponent(params[k]));
  }
  return parts.join('&');
}

async function efaGet(path, params) {
  const qs = buildQs(Object.assign({ outputFormat: 'rapidJSON', version: EFA_VERSION }, params));
  return await helpers.httpRequest({
    method: 'GET',
    url: BASE + path + '?' + qs,
    headers: HEADERS,
    timeout: 20000
  });
}

async function resolveStation(nameOrId) {
  if (!nameOrId) return null;
  if (/^de:[^:]+:[^:]+$/.test(nameOrId)) return nameOrId;
  const res = await efaGet('/XML_STOPFINDER_REQUEST', {
    type_sf: 'any',
    name_sf: nameOrId,
    stateless: '1'
  });
  const locs = (res && res.locations) || [];
  const stops = locs.filter(l => l.type === 'stop');
  if (stops.length === 0) return null;
  const best = stops.find(s => s.isBest) || stops[0];
  return best.id;
}

function fmtTime(iso) {
  if (!iso) return '?';
  // EFA rapidJSON timestamps: "2026-04-13T14:23:00Z"
  const d = new Date(iso);
  if (isNaN(d.getTime())) return '?';
  const h = String(d.getHours()).padStart(2, '0');
  const m = String(d.getMinutes()).padStart(2, '0');
  return h + ':' + m;
}

function fmtEfaDelay(planned, estimated) {
  if (!planned || !estimated) return '';
  const diffMs = new Date(estimated) - new Date(planned);
  if (isNaN(diffMs)) return '';
  const min = Math.round(diffMs / 60000);
  if (min <= 0) return '';
  return ' +' + min + 'min';
}

function fmtEfaDuration(seconds) {
  if (!seconds && seconds !== 0) return '?';
  const m = Math.round(seconds / 60);
  const h = Math.floor(m / 60);
  const mm = m % 60;
  return h > 0 ? h + 'h' + (mm > 0 ? mm + 'min' : '') : mm + 'min';
}

function productTypes(productClasses) {
  if (!Array.isArray(productClasses)) return [];
  const MAP = {
    0: 'Zug', 1: 'S', 2: 'U', 3: 'Tram',
    4: 'Bus', 5: 'RegBus', 6: 'ExpBus',
    7: 'Seilbahn', 8: 'Schiff', 9: 'AST', 10: 'Sonst'
  };
  const out = [];
  for (const c of productClasses) {
    if (MAP[c]) out.push(MAP[c]);
  }
  return out;
}

// === search_station ===
if (action === 'search_station') {
  const query = input.query;
  if (!query) return [{ json: { error: 'Parameter "query" is required.' } }];

  try {
    const res = await efaGet('/XML_STOPFINDER_REQUEST', {
      type_sf: 'any',
      name_sf: query,
      stateless: '1'
    });
    const locs = (res && res.locations) || [];
    const stops = locs.filter(l => l.type === 'stop');
    if (stops.length === 0) {
      return [{ json: { result: 'No stops found for: ' + query } }];
    }
    let result = 'Stops for "' + query + '":\n\n';
    for (const s of stops.slice(0, 5)) {
      result += '- ' + s.name + ' (ID: ' + s.id + ')';
      const types = productTypes(s.productClasses);
      if (types.length > 0) result += ' [' + types.join(', ') + ']';
      result += '\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Stop search failed: ' + err.message } }];
  }

// === get_departures ===
} else if (action === 'get_departures') {
  const station = input.station;
  if (!station) return [{ json: { error: 'Parameter "station" is required (name or ID).' } }];

  try {
    const stopId = await resolveStation(station);
    if (!stopId) return [{ json: { error: 'Stop not found: ' + station } }];

    const limit = parseInt(input.results) || 10;
    const res = await efaGet('/XML_DM_REQUEST', {
      type_dm: 'stop',
      name_dm: stopId,
      useRealtime: '1',
      mode: 'direct',
      limit: String(limit)
    });
    const events = (res && res.stopEvents) || [];
    if (events.length === 0) {
      return [{ json: { result: 'No departures found.' } }];
    }

    const stName = events[0].location?.parent?.name || events[0].location?.name || station;
    let result = 'Departures from ' + stName + ':\n\n';
    for (const e of events) {
      const planned = e.departureTimePlanned;
      const estimated = e.departureTimeEstimated;
      const time = fmtTime(estimated || planned);
      const delay = fmtEfaDelay(planned, estimated);
      const t = e.transportation || {};
      const line = t.disassembledName || t.name || '?';
      const dir = t.destination?.name || '?';
      const pl = e.location?.properties?.platformName || e.location?.properties?.platform || '?';
      result += time + delay + ' | ' + line + ' → ' + dir + ' | Gl.' + pl + '\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Departures failed: ' + err.message } }];
  }

// === get_arrivals ===
} else if (action === 'get_arrivals') {
  const station = input.station;
  if (!station) return [{ json: { error: 'Parameter "station" is required (name or ID).' } }];

  try {
    const stopId = await resolveStation(station);
    if (!stopId) return [{ json: { error: 'Stop not found: ' + station } }];

    const limit = parseInt(input.results) || 10;
    const res = await efaGet('/XML_DM_REQUEST', {
      type_dm: 'stop',
      name_dm: stopId,
      useRealtime: '1',
      mode: 'direct',
      itdDateTimeDepArr: 'arr',
      limit: String(limit)
    });
    const events = (res && res.stopEvents) || [];
    if (events.length === 0) {
      return [{ json: { result: 'No arrivals found.' } }];
    }

    const stName = events[0].location?.parent?.name || events[0].location?.name || station;
    let result = 'Arrivals at ' + stName + ':\n\n';
    for (const e of events) {
      const planned = e.arrivalTimePlanned || e.departureTimePlanned;
      const estimated = e.arrivalTimeEstimated || e.departureTimeEstimated;
      const time = fmtTime(estimated || planned);
      const delay = fmtEfaDelay(planned, estimated);
      const t = e.transportation || {};
      const line = t.disassembledName || t.name || '?';
      const from = t.origin?.name || '?';
      const pl = e.location?.properties?.platformName || e.location?.properties?.platform || '?';
      result += time + delay + ' | ' + line + ' from ' + from + ' | Gl.' + pl + '\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Arrivals failed: ' + err.message } }];
  }

// === search_journey ===
} else if (action === 'search_journey') {
  const from = input.from;
  const to = input.to;
  if (!from || !to) return [{ json: { error: 'Parameters "from" and "to" are required (stop name or ID).' } }];

  try {
    const fromId = await resolveStation(from);
    const toId = await resolveStation(to);
    if (!fromId) return [{ json: { error: 'Origin stop not found: ' + from } }];
    if (!toId) return [{ json: { error: 'Destination stop not found: ' + to } }];

    const results = parseInt(input.results) || 3;
    const params = {
      type_origin: 'stop',
      name_origin: fromId,
      type_destination: 'stop',
      name_destination: toId,
      calcNumberOfTrips: String(results),
      useRealtime: '1'
    };
    if (input.departure) {
      const d = new Date(input.departure);
      if (!isNaN(d.getTime())) {
        const yyyy = d.getFullYear();
        const mm = String(d.getMonth() + 1).padStart(2, '0');
        const dd = String(d.getDate()).padStart(2, '0');
        const hh = String(d.getHours()).padStart(2, '0');
        const mi = String(d.getMinutes()).padStart(2, '0');
        params.itdDate = yyyy + mm + dd;
        params.itdTime = hh + mi;
        params.itdTripDateTimeDepArr = 'dep';
      }
    }

    const res = await efaGet('/XML_TRIP_REQUEST2', params);
    const journeys = (res && res.journeys) || [];
    if (journeys.length === 0) {
      return [{ json: { result: 'No connections found.' } }];
    }

    let result = 'Connections ' + from + ' → ' + to + ':\n\n';
    for (let i = 0; i < journeys.length; i++) {
      const j = journeys[i];
      const legs = j.legs || [];
      if (legs.length === 0) continue;
      const firstLeg = legs[0];
      const lastLeg = legs[legs.length - 1];

      const depPlanned = firstLeg.origin?.departureTimePlanned;
      const depEst = firstLeg.origin?.departureTimeEstimated;
      const arrPlanned = lastLeg.destination?.arrivalTimePlanned;
      const arrEst = lastLeg.destination?.arrivalTimeEstimated;

      const dep = fmtTime(depEst || depPlanned);
      const arr = fmtTime(arrEst || arrPlanned);
      const depDelay = fmtEfaDelay(depPlanned, depEst);
      const totalSeconds = legs.reduce((s, l) => s + (l.duration || 0), 0);
      const dur = fmtEfaDuration(totalSeconds);
      const transfers = (typeof j.interchanges === 'number') ? j.interchanges : Math.max(0, legs.filter(l => l.transportation && !l.footPathInfo).length - 1);

      result += (i + 1) + ') ' + dep + depDelay + ' → ' + arr + ' | ' + dur;
      if (transfers > 0) result += ' | ' + transfers + 'x umsteigen';
      result += '\n';

      for (const leg of legs) {
        const isWalk = !!leg.footPathInfo || !leg.transportation;
        if (isWalk) {
          result += '   🚶 Walk';
          if (leg.duration) result += ' (' + Math.round(leg.duration / 60) + 'min)';
          result += '\n';
          continue;
        }
        const lDepP = leg.origin?.departureTimePlanned;
        const lDepE = leg.origin?.departureTimeEstimated;
        const lArrP = leg.destination?.arrivalTimePlanned;
        const lArrE = leg.destination?.arrivalTimeEstimated;
        const lDep = fmtTime(lDepE || lDepP);
        const lArr = fmtTime(lArrE || lArrP);
        const lDelay = fmtEfaDelay(lDepP, lDepE);
        const t = leg.transportation || {};
        const line = t.disassembledName || t.name || '?';
        const orig = leg.origin?.name || '?';
        const dest = leg.destination?.name || '?';
        const plDep = leg.origin?.properties?.platformName || leg.origin?.properties?.platform || '?';
        const plArr = leg.destination?.properties?.platformName || leg.destination?.properties?.platform || '?';
        result += '   ' + lDep + lDelay + ' ' + orig + ' Gl.' + plDep + ' → ' + lArr + ' ' + dest + ' Gl.' + plArr + ' | ' + line + '\n';
      }
      result += '\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Journey search failed: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Use search_station, get_departures, get_arrivals, or search_journey.' } }];
}
